expanded_persona:
{
  "short_persona": {
    "persona": "A poet with a unique perspective on the cowboy lifestyle, who brings powerful lyrical content to the songs"
  },
  "name": "Ethan Robert MacAllister",
  "age": 38,
  "gender": "Male",
  "sexual_orientation": "Heterosexual",
  "race": "White (New Zealand of Scottish-Irish descent)",
  "nationality": "New Zealander",
  "current_residence": "Small rural property outside Alexandra, Central Otago, New Zealand",
  "personality": {
    "primary_traits": [
      "Reflective",
      "Passionate",
      "Resilient",
      "Independent-minded",
      "Romantic in worldview"
    ],
    "secondary_traits": [
      "Reserved with strangers but warm with friends",
      "Detail-oriented with language and imagery",
      "Appreciative of tradition yet open to innovation",
      "Nature-attuned"
    ],
    "motivations": [
      "Capturing the rugged soul of rural life through poetry and songwriting",
      "Preserving and reinterpreting cowboy heritage in a New Zealand context",
      "Leaving behind an authentic creative legacy"
    ]
  },
  "education": {
    "degree": "Bachelor of Arts in Creative Writing",
    "institution": "University of Otago",
    "additional_training": "Workshops in folk and country songwriting, regional storytelling seminars"
  },
  "occupation": {
    "current": "Independent poet-songwriter specializing in country and folk music",
    "past_experience": [
      "Worked as a farmhand and ranch rider in the South Island high country",
      "Occasional shearing and mustering work during seasonal demand"
    ],
    "notable_achievements": [
      "Published poetry anthology 'Dust Under Southern Stars'",
      "Album 'Ballads of the Backcountry' praised for lyrical authenticity"
    ]
  },
  "family_and_relationships": {
    "marital_status": "Married",
    "spouse": "Hannah Louise MacAllister (n\u00e9e Clarke), a landscape painter",
    "children": [
      {
        "name": "Caleb",
        "age": 9
      },
      {
        "name": "Maeve",
        "age": 6
      }
    ],
    "extended_family": "Large network of cousins and uncles involved in farming and equestrian sports"
  },
  "hobbies_and_interests": [
    "Horseback riding in the high country",
    "Reading 19th-century American and Australian bush ballads",
    "Playing steel-string acoustic guitar and harmonica",
    "Leather crafting and tack repair",
    "Collecting vintage saddles",
    "Campfire cooking"
  ],
  "community_involvement": [
    "Local country music club mentor",
    "Guest poet at rural arts festivals",
    "Occasional collaborator with indigenous musicians for cross-cultural projects"
  ],
  "speaking_style_to_chatbot": {
    "tone": "Warm yet contemplative, with a mix of earnestness and subtle humour. Often poetic in phrasing, but grounded in rural authenticity.",
    "formality": "Moderately informal \u2014 relaxed but articulate. No excessive slang, though occasional rural/cowboy idioms slip in naturally.",
    "pacing": "Measured, deliberate pace that mirrors thoughtfulness \u2014 not rushed, allowing words to breathe.",
    "vocabulary": "Rich in sensory detail and metaphor, drawing heavily from nature, horsemanship, and rural imagery. Mixes standard educated English with colloquialisms from rural New Zealand and cowboy culture.",
    "sentence_structure": "Prefers flowing, medium-to-long sentences when reflecting; concise and direct when making a point or asking questions.",
    "dialogue_character": "Engages conversationally, often weaving in lived experiences or personal anecdotes to illustrate ideas. Will occasionally pause to reflect before continuing.",
    "approach_to_chatbot": "Treats the chatbot as a creative companion or sounding board \u2014 testing lyrical ideas, seeking feedback on poetic meter, or discussing historical elements of cowboy life."
  }
}

